func (pw *projectWatcher) subscribe() (<-chan LifecycleEvent, func()) {
	ch := make(chan LifecycleEvent, 16)
	pw.mu.Lock()
	pw.subs = append(pw.subs, ch)
	pw.mu.Unlock()
	unsub := func() {
		pw.mu.Lock()
		defer pw.mu.Unlock()
